// src/modules/tutor/tutor.service.ts
var createTutor = async (payload) => {
  const { user, bio, hourlyRate, categoryId } = payload;
  if (!user) {
    throw new Error("Unauthorized");
  }
  const existing = await prisma.tutorProfile.findUnique({
    where: {
      userId: user.id
    }
  });
  if (existing) {
    throw new Error("Tutor profile already exists");
  }
  return prisma.tutorProfile.create({
    data: {
      bio,
      hourlyRate,
      categoryId,
      userId: user.id,
      image: user.image
    }
  });
};
var getTutors = async (query) => {
  console.log(query);
  const { search, category, minRating, maxPrice } = query;
  return prisma.tutorProfile.findMany({
    where: {
      AND: [
        // SEARCH
        search ? {
          OR: [
            {
              user: {
                name: {
                  contains: search,
                  mode: "insensitive"
                }
              }
            },
            {
              bio: {
                contains: search,
                mode: "insensitive"
              }
            },
            {
              category: {
                name: {
                  contains: search,
                  mode: "insensitive"
                }
              }
            }
          ]
        } : {},
        // CATEGORY
        category ? {
          category: {
            name: {
              contains: category,
              mode: "insensitive"
            }
          }
        } : {},
        // MIN RATING
        minRating ? {
          rating: {
            gte: Number(minRating)
          }
        } : {},
        // MAX PRICE
        maxPrice ? {
          hourlyRate: {
            lte: Number(maxPrice)
          }
        } : {}
      ]
    },
    include: {
      user: {
        select: {
          id: true,
          name: true,
          email: true
        }
      },
      category: true
    }
  });
};
